import { useState } from "react";
import { AppHeader } from "@/components/app-header";
import { CreateCampaignModal } from "@/components/create-campaign-modal";
import { fetchCampaignsList } from "@/routes/_authed/campaigns/-campaigns";
import { getAppBootstrapData } from "@/server/app-bootstrap";
import { OrgApiError } from "@/server/error";
import {
  createFileRoute,
  getRouteApi,
  Link,
  redirect,
  useNavigate,
} from "@tanstack/react-router";
import { createServerFn } from "@tanstack/react-start";
import { Badge, Button, Card } from "@workspace/ui";
import {
  ArrowRight,
  Check,
  ChevronRight,
  Copy,
  Plus,
  Settings,
  Target,
} from "lucide-react";

type DashboardCampaign = {
  id: number;
  name: string;
};

type DashboardPageData = {
  campaigns: DashboardCampaign[];
  cards: {
    campaigns: number;
    payouts: number;
    transactions: number;
  };
};

const getDashboardData = createServerFn({ method: "GET" }).handler(
  async () => {
    try {
      const bootstrap = await getAppBootstrapData();
      if (!bootstrap?.currentTenant) {
        throw redirect({ to: "/login" });
      }

      const campaigns = (await fetchCampaignsList()) ?? [];
      const simplified = campaigns.map((c) => ({ id: c.id, name: c.name }));

      return {
        campaigns: simplified,
        cards: {
          campaigns: simplified.length,
          payouts: 7,
          transactions: 428,
        },
      } satisfies DashboardPageData;
    } catch (error) {
      if (error instanceof OrgApiError && error.status === 401) {
        throw redirect({ to: "/login" });
      }

      throw error;
    }
  },
);
